import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"Epic: Activity Logs","description":"","frontmatter":{},"headers":[],"relativePath":"epics/activity-logs.md","filePath":"epics/activity-logs.md"}'),s={name:"epics/activity-logs.md"};function c(n,e,r,l,d,u){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="epic-activity-logs" tabindex="-1">Epic: Activity Logs <a class="header-anchor" href="#epic-activity-logs" aria-label="Permalink to &quot;Epic: Activity Logs&quot;">​</a></h1><blockquote><p>A tamper-evident audit trail of user and admin actions across the platform, surfaced in both the Account plugin (personal feed) and the Console (platform-wide feed).</p></blockquote><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>✅ Complete</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Activity logging gives operators and users visibility into what happened and when. The platform captures Console admin actions (invite, role change, deactivate, plugin enable/disable, settings changes) and Account self-mutations (display name, password change, session revoke, avatar). Plugins write their own events via <code>sdk.activity.log()</code>. The Account plugin shows a personal feed; Console shows the platform-wide feed with actor, action, scope, and summary columns.</p><h2 id="tasks" tabindex="-1">Tasks <a class="header-anchor" href="#tasks" aria-label="Permalink to &quot;Tasks&quot;">​</a></h2><h4 id="✅-5-1-—-activity-log-rfc-0005" tabindex="-1">✅ 5.1 — Activity log (RFC 0005) <a class="header-anchor" href="#✅-5-1-—-activity-log-rfc-0005" aria-label="Permalink to &quot;✅ 5.1 — Activity log (RFC 0005)&quot;">​</a></h4><p><strong>Delivered:</strong></p><ul><li><code>activity_log</code> table in both SQLite and Postgres schemas (parity-tested); <code>recordActivity()</code>, <code>listUserActivity()</code>, <code>listAdminActivity()</code> helpers in <code>@sovereignfs/db</code> (→ 0.9.0); bootstrap DDL with three indexes</li><li><code>sdk.activity.log()</code> implemented (no longer a stub): reads actor/plugin from request headers via the <code>SdkHost.activity.log()</code> contract; runtime injects actor type and namespaces action by plugin ID; <code>activity:write</code> permission documented (<code>@sovereignfs/sdk</code> → 1.3.0)</li><li>Capture points: Console user-management actions (invite, role change, deactivate/reactivate), admin plugin enable/disable, admin settings changes (tenant name, root plugin, invite-only), Account self-mutations (display name, password change, session revoke, avatar)</li><li>API routes: <code>GET /api/account/activity</code> (personal feed, session-gated) and <code>GET /api/admin/activity</code> (platform-wide, admin-key-gated with <code>actorId</code>/<code>action</code>/<code>limit</code> filters)</li><li>Account <strong>Activity</strong> tab (<code>/account/activity</code>) — personal feed, all users; Console <strong>Activity</strong> nav entry + page (<code>/console/activity</code>) — platform-wide feed with actor, action, summary, scope columns</li><li><code>runtime/src/activity.ts</code> <code>logActivity()</code> — fire-and-forget wrapper used by runtime routes; never throws so a log failure never blocks the primary action</li><li><code>runtime</code> → 0.14.0; <code>plugins/account</code> → 0.4.0; <code>plugins/console</code> → 0.5.0</li></ul><p><strong>Deferred:</strong> Login/session-established capture at the runtime verify boundary (Edge runtime cannot write the platform DB; deferred to a follow-on task per RFC 0005 §3 open question).</p><hr><h2 id="related-rfcs" tabindex="-1">Related RFCs <a class="header-anchor" href="#related-rfcs" aria-label="Permalink to &quot;Related RFCs&quot;">​</a></h2><ul><li><a href="./../rfcs/0005-activity-log.html">RFC 0005 — Activity log</a></li></ul><h2 id="related-docs" tabindex="-1">Related Docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related Docs&quot;">​</a></h2><ul><li><a href="./../plugin-development.html">plugin-development.md — <code>sdk.activity</code></a></li></ul><h2 id="cross-references" tabindex="-1">Cross-references <a class="header-anchor" href="#cross-references" aria-label="Permalink to &quot;Cross-references&quot;">​</a></h2><ul><li>The Account plugin&#39;s Activity tab (<code>/account/activity</code>) is part of <a href="./plugin-accounts.html">Plugin — Accounts</a>.</li><li>The Console Activity page (<code>/console/activity</code>) is part of <a href="./plugin-console.html">Plugin — Console</a>.</li></ul>',18)])])}const v=t(s,[["render",c]]);export{h as __pageData,v as default};
